/**
 * Audit Log Page
 *
 * Admin page for viewing audit logs of admin operations.
 * Features:
 * - Audit log list with timestamp, operation, admin email, target user, success/failure
 * - Filter by operation type
 */

import React, { useState, useEffect } from 'react';
import { useAdmin } from '../../hooks/useAdmin';
import type { AuditLogEntryDto } from 'shared';
import LoadingSpinner from '../../components/LoadingSpinner';
import ErrorMessage from '../../components/ErrorMessage';
import AdminPageHeader from '../../components/AdminPageHeader';

type OperationType =
  | 'admin.createUser'
  | 'admin.deleteUser'
  | 'admin.enableUser'
  | 'admin.disableUser'
  | 'admin.resetPassword'
  | 'admin.promoteToAdmin';

const OPERATION_LABELS: Record<OperationType, string> = {
  'admin.createUser': 'Create User',
  'admin.deleteUser': 'Delete User',
  'admin.enableUser': 'Enable User',
  'admin.disableUser': 'Disable User',
  'admin.resetPassword': 'Reset Password',
  'admin.promoteToAdmin': 'Promote to Admin',
};

const AuditLogPage: React.FC = () => {
  const admin = useAdmin();
  const [logs, setLogs] = useState<AuditLogEntryDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [operationFilter, setOperationFilter] = useState<string>('');

  const fetchLogs = async (operation?: string) => {
    setLoading(true);
    setError(null);
    try {
      const params: { limit?: number; operation?: string } = { limit: 100 };
      if (operation) {
        params.operation = operation;
      }
      const response = await admin.getAuditLogs(params);
      setLogs(response.logs);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch audit logs');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLogs();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleFilterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    setOperationFilter(value);
    fetchLogs(value || undefined);
  };

  const formatTimestamp = (timestamp: string) => {
    return new Date(timestamp).toLocaleString();
  };

  const getOperationLabel = (operation: string) => {
    return OPERATION_LABELS[operation as OperationType] ?? operation;
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <AdminPageHeader
        title="Audit Logs"
        action={{ label: 'Refresh', onClick: () => fetchLogs(operationFilter || undefined) }}
      />

      {/* Filter */}
      <div className="mb-6">
        <label htmlFor="operation-filter" className="block text-sm font-medium text-gray-700 mb-1">
          Filter by Operation
        </label>
        <select
          id="operation-filter"
          value={operationFilter}
          onChange={handleFilterChange}
          className="px-4 py-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="">All Operations</option>
          {(Object.keys(OPERATION_LABELS) as OperationType[]).map((op) => (
            <option key={op} value={op}>
              {OPERATION_LABELS[op]}
            </option>
          ))}
        </select>
      </div>

      {/* Error Message */}
      {error && <ErrorMessage message={error} />}

      {/* Loading Spinner */}
      {loading && (
        <div className="flex justify-center py-8">
          <LoadingSpinner size="large" text="Loading audit logs..." />
        </div>
      )}

      {/* Audit Log Table */}
      {!loading && !error && (
        <>
          <div className="bg-white shadow-md rounded overflow-x-auto">
            <table className="min-w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Timestamp
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Operation
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Admin
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Target User
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Result
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {logs.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-4 text-center text-gray-500">
                      No audit logs found
                    </td>
                  </tr>
                ) : (
                  logs.map((log, index) => (
                    <tr key={`${log.timestamp}-${index}`} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {formatTimestamp(log.timestamp)}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-blue-100 text-blue-800">
                          {getOperationLabel(log.operation)}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {log.adminEmail}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {log.targetUserEmail ?? '-'}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        {log.success ? (
                          <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">
                            Success
                          </span>
                        ) : (
                          <span
                            className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-red-100 text-red-800"
                            title={log.error ?? undefined}
                          >
                            Failed
                          </span>
                        )}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          <div className="mt-4 text-sm text-gray-500">
            {logs.length} log{logs.length !== 1 ? 's' : ''} found
          </div>
        </>
      )}
    </div>
  );
};

export default AuditLogPage;
